  // Normalize: ensure all referenced children exist in fileSystem
  function normalizeFS() {
    const queue = ['/'];
    const visited = new Set(['/']);
    while (queue.length) {
      const path = queue.shift();
      const entry = fileSystem[path];
      if (!entry || entry.type !== 'dir') continue;
      for (const child of entry.children) {
        const childPath = path === '/' ? '/' + child : path + '/' + child;
        if (!fileSystem[childPath]) {
          fileSystem[childPath] = { type: 'dir', children: [] };
        }
        if (!visited.has(childPath)) {
          visited.add(childPath);
          queue.push(childPath);
        }
      }
    }
  }
  normalizeFS();

  // ===== Files App =====
  let filesCurrentPath = '/';

  function filesRender() {
    const pathInput = document.getElementById('files-path');
    const listEl = document.getElementById('files-list');
    pathInput.value = filesCurrentPath;

    const entry = fileSystem[filesCurrentPath];
    if (!entry || entry.type !== 'dir') {
      listEl.innerHTML = '<p style="color:#888;padding:20px;">Directory not found.</p>';
      return;
    }

    listEl.innerHTML = '';
    const children = entry.children || [];
    // Sort: dirs first, then files
    const sorted = children.sort((a, b) => {
      const aPath = filesCurrentPath === '/' ? '/' + a : filesCurrentPath + '/' + a;
      const bPath = filesCurrentPath === '/' ? '/' + b : filesCurrentPath + '/' + b;
      const aIsDir = (fileSystem[aPath] && fileSystem[aPath].type === 'dir') || fileSystem[a] && fileSystem[a].type === 'dir';
      const bIsDir = (fileSystem[bPath] && fileSystem[bPath].type === 'dir') || fileSystem[b] && fileSystem[b].type === 'dir';
      if (aIsDir && !bIsDir) return -1;
      if (!aIsDir && bIsDir) return 1;
      return a.localeCompare(b);
    });

    for (const name of sorted) {
      const itemPath = filesCurrentPath === '/' ? '/' + name : filesCurrentPath + '/' + name;
      const isDir = (fileSystem[itemPath] && fileSystem[itemPath].type === 'dir') ||
                    (fileSystem[name] && fileSystem[name].type === 'dir');
      const div = document.createElement('div');
      div.className = 'fs-item' + (isDir ? ' folder' : ' file');
      div.innerHTML = '<span class="fs-icon">' + (isDir ? '📁' : '📄') + '</span><span class="fs-name">' + name + '</span>';
      if (isDir) {
        div.addEventListener('dblclick', function() {
          filesCurrentPath = itemPath;
          filesRender();
        });
      }
      listEl.appendChild(div);
    }
  }

